import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as n,e as r}from"./app-01aedd85.js";const e={},o=r('<h1 id="rag存在的问题和解决思路" tabindex="-1"><a class="header-anchor" href="#rag存在的问题和解决思路" aria-hidden="true">#</a> RAG存在的问题和解决思路</h1><h3 id="一、文档层-document-layer-问题" tabindex="-1"><a class="header-anchor" href="#一、文档层-document-layer-问题" aria-hidden="true">#</a> <strong>一、文档层（Document Layer）问题</strong></h3><ul><li><strong>1. PDF / Office 文档格式混乱</strong></li></ul><p>问题：PDF 结构丢失、段落断裂、表格识别错误、图像关联中断。</p><p>解决方案：文档结构化解析（Document Normalization），多模态解析。</p><ul><li><p><strong>文字/图像/表格之间的关联关系丢失</strong></p><p>表格 + 解释性文本 绑定为一个 chunk</p><p>图像 + caption + 引用段落 绑定为一个 multimodal block</p><p>采用 <strong>多模态 embedding（CLIP / siglip / Voyage-multimodal）</strong></p></li><li><p><strong>Chunk 边界断裂（Chunking 不感知结构）</strong></p></li><li><p>滑动窗口分块</p></li><li><p>表格、图像不切碎，保持单独 chunk</p></li><li><p>基于标题层级/段落</p></li><li><p><strong>多文档版本混乱（旧版手册与新版矛盾）</strong></p><ul><li>元数据过滤</li><li>检索时指定版本</li><li>生成时表明冲突</li></ul></li><li><p><strong>多语言文档混合（中英并存）</strong></p><ul><li>索引时多语言</li><li>检索时中英结合</li></ul></li><li><p><strong>专业领域知识</strong></p><ul><li>Embedding微调</li></ul></li></ul><h3 id="二、检索层-retrieval-layer-问题" tabindex="-1"><a class="header-anchor" href="#二、检索层-retrieval-layer-问题" aria-hidden="true">#</a> <strong>二、检索层（Retrieval Layer）问题</strong></h3><ul><li><p><strong>6. Embedding 偏差、领域漂移</strong>embedding 对行业术语（如 SMU、Id-Vgs）不敏感。</p><ul><li>领域数据微调 embedding</li><li>添加领域词表</li></ul></li><li><p><strong>7. 稠密向量检索召回不够</strong></p><ul><li>多路召回。BM25，向量，关键字，知识图谱</li></ul></li><li><p><strong>8. 多模态信息无法召回（图像/表格找不到）</strong></p><ul><li>索引时应该使用多模态模型处理</li></ul></li><li><p><strong>9. 多文档可信度排序</strong></p><ul><li>初级检索：向量召回 top-k</li><li>高级重排（rerank）：Cross-Encoder（如 bge-reranker）</li><li>先规则后向量，最后重排。元数据优先级</li></ul></li><li><p><strong>10. 权限隔离缺失（A/B 团队数据暴露）</strong></p><ul><li>添加 metadata：<code>team</code>, <code>user_id</code>, <code>department</code></li><li>检索时 vector DB 层过滤权限</li></ul></li><li><p><strong>11. 零样本/长尾查询无法召回</strong></p></li><li><p>查询重写</p></li><li><p>知识图谱</p></li><li><p>HYDE</p></li><li><p><strong>12. 检索可解释性缺失</strong></p><ul><li>返回匹配字段 + 相似度 score</li><li>多路召回</li></ul></li></ul><h3 id="三、推理层-reasoning-layer-问题" tabindex="-1"><a class="header-anchor" href="#三、推理层-reasoning-layer-问题" aria-hidden="true">#</a> <strong>三、推理层（Reasoning Layer）问题</strong></h3><ul><li><strong>13. 多源文档互相矛盾 → 放大幻觉</strong></li><li>规则排序</li><li>若冲突存在 → 在答案中明确列出：</li><li><strong>14.</strong> <strong>LLM</strong> <strong>不引用检索结果，自己胡编</strong><ul><li>提示词优化，规则放后面</li><li>json结构化输出</li><li>检索的数据太多，噪声太大，优化检索结果</li><li>反思模型</li></ul></li><li><strong>15. LLM 没能利用所有检索结果（Fusion Poor）</strong><ul><li>检索融合</li><li>反思模型</li></ul></li><li><strong>16. 跨 chunk 依赖关系缺失（long-range dependency）</strong><ul><li>GraphRAG（知识图谱 + 文本图）</li><li>小文本检索，大文本召回</li></ul></li></ul><h3 id="四、更新层-ingestion-index-问题" tabindex="-1"><a class="header-anchor" href="#四、更新层-ingestion-index-问题" aria-hidden="true">#</a> <strong>四、更新层（Ingestion &amp; Index）问题</strong></h3><ul><li><p><strong>17. 文档频繁更新无法实时同步</strong></p><ul><li>增量更新（Incremental Indexing）</li><li>基于 hash 的 chunk 稳定 ID</li></ul></li><li><p><strong>18. 大量文档更新导致向量库膨胀</strong></p><ul><li>对旧版本自动下架（soft delete）</li><li>周期性 GC（清理废弃向量）</li><li>低频访问内容转离线存储</li></ul></li></ul>',12),t=[o];function s(a,g){return i(),n("div",null,t)}const u=l(e,[["render",s],["__file","15、RAG系统可能遇到的问题.html.vue"]]);export{u as default};
